def _extract_ac6_ticket_section(text: str) -> str:
    """Extract text from '### AC6' heading to the next '### AC7' heading (exclusive)."""
    start_match = re.search(r"^### AC6\b", text, re.MULTILINE)
    end_match   = re.search(r"^### AC7\b", text, re.MULTILINE)
    if not start_match:
        return ""
    end = end_match.start() if end_match else len(text)
    return text[start_match.start():end]


